sys_script.script:
(function executeRule(current, previous) {

    // gs.info("===== Async Started =====", "CityMed");

    // gs.info("Equipment = " + current.equipment_id, "CityMed");

    var faultCount = 0;

    var thirtyDaysAgo = new GlideDateTime();
    thirtyDaysAgo.addDaysUTC(-30);

    var gr = new GlideRecord('x_2057380_cityme_0_equipment_fault');
    gr.addQuery('equipment_id', current.equipment_id);
    gr.addQuery('sys_created_on', '>=', thirtyDaysAgo);
    gr.query();

    while (gr.next()) {
        faultCount++;
    }

    // gs.info("Fault Count = " + faultCount, "CityMed");

    if (faultCount > 3) {

        // gs.info("Condition Passed", "CityMed");

        var updateGR = new GlideRecord('x_2057380_cityme_0_equipment_fault');

        if (updateGR.get(current.sys_id)) {

            updateGR.work_notes =
                "Warning: This equipment has logged " +
                faultCount +
                " faults.";

            updateGR.update();

            gs.info("Async BR Executed and Updated Successfully", "CityMed");
        }
    }

})(current, previous);
